1	// ─── Checkout lifecycle ───────────────────────────────────────────────────────
2	
3	export type CheckoutStatus =
4	  | "active"
5	  | "checkin_queued"
6	  | "uploading"
7	  | "verifying"
8	  | "complete"
9	  | "discarded"
10	  | "error"
11	  | "conflict";
12	
13	export interface CheckoutRecord {
14	  id: string;                  // UUID from DB
15	  assetId: string;
16	  userId: string;
17	  deviceId: string | null;
18	  status: CheckoutStatus;
19	  checkedOutAt: string;        // ISO timestamp
20	  checkedInAt: string | null;
21	  // Asset info
22	  filename: string;
23	  relativePath: string;
24	  rootId: string;
25	  // File state
26	  sourceHash: string;
27	  sourceSize: number;
28	  // Local paths (machine-specific, not in DB)
29	  workspacePath: string;
30	  snapshotPath: string | null;
31	  // Upload progress (in-memory only)
32	  uploadProgress: number | null; // 0–100
33	  errorMessage: string | null;
34	}
35	
36	// ─── Root validation ──────────────────────────────────────────────────────────
37	
38	export type ValidationResult =
39	  | { ok: true; resolvedPath: string }
40	  | { ok: false; reason: "forbidden"; message: string }
41	  | { ok: false; reason: "no_marker"; message: string }
42	  | { ok: false; reason: "wrong_root_id"; expected: string; actual: string; message: string }
43	  | { ok: false; reason: "too_deep"; suggestedPath: string; message: string }
44	  | { ok: false; reason: "too_shallow"; suggestedPath: string; message: string };
45	
