47	
48	export interface RootMapping {
49	  root_id: string;           // e.g. "design_hot"
50	  display_name: string;      // e.g. "Design Hot"
51	  local_path: string;        // e.g. "C:\\Users\\Maria\\Seafile\\Design_Hot"
52	  marker_verified: boolean;
53	}
