58	  deviceId: string | null;
59	  deviceName: string;
60	  deviceOs: "windows" | "macos";
61	  helperVersion: string;
62	  damUrl: string;
63	  supabaseUrl: string;        // API base URL — auto-discovered from ${damUrl}/dam-config.json
64	  supabaseAnonKey: string;    // Public anon key — auto-discovered from ${damUrl}/dam-config.json
65	  workspacePath: string;
66	  rootMappings: RootMapping[];
