1	/**
2	 * Checkout state machine — coordinates the full checkout/check-in lifecycle.
3	 * This is the orchestrator: it calls damClient, fileOps, uploadQueue, and
4	 * chokidar to drive a checkout from start to finish.
5	 */
6	
7	import { shell } from "electron";
8	import chokidar, { FSWatcher } from "chokidar";
9	import { existsSync, statSync } from "fs";
10	import { join, dirname, basename } from "path";
11	import {
12	  resolveAssetPath,
13	  copyToWorkspace,
14	  writeCheckoutMeta,
15	  waitForFileStable,
16	  createSnapshot,
17	  checkoutDir,
18	} from "./fileOps";
19	import { sha256File } from "./hash";
20	import {
21	  startCheckout as apiStartCheckout,
22	  prepareCheckin as apiPrepareCheckin,
23	  discardCheckout as apiDiscard,
24	  getOpenCheckouts,
25	} from "./damClient";
26	import { enqueue } from "./uploadQueue";
27	import { getConfig } from "./config";
28	import { validateRoot } from "./rootValidator";
29	import { log } from "./logger";
30	import type { CheckoutRecord, RootMapping } from "@shared/types";
31	
32	// In-memory map of active checkouts: checkoutId → record
33	const active = new Map<string, CheckoutRecord>();
34	// File watchers keyed by checkoutId
35	const watchers = new Map<string, FSWatcher>();
36	
37	let changeListener: (() => void) | null = null;
38	
39	export function onCheckoutsChanged(cb: () => void): void {
40	  changeListener = cb;
41	}
42	
43	function notify(): void {
44	  changeListener?.();
45	}
46	
47	// ── Load from server on startup ───────────────────────────────────────────────
48	
49	export async function loadActiveCheckouts(): Promise<void> {
50	  try {
51	    const res = await getOpenCheckouts();
52	    const config = getConfig();
53	    for (const co of res.checkouts ?? []) {
54	      const assetInfo = (co as any).assets ?? {};
55	      const record: CheckoutRecord = {
56	        id: co.id,
57	        assetId: assetInfo.id ?? "",
58	        userId: "",
59	        deviceId: null,
60	        status: co.status as CheckoutRecord["status"],
61	        checkedOutAt: co.checked_out_at,
62	        checkedInAt: null,
63	        filename: assetInfo.filename ?? "",
64	        relativePath: assetInfo.relative_path ?? "",
65	        rootId: "",
66	        sourceHash: co.source_hash,
67	        sourceSize: co.source_size,
68	        workspacePath: join(
69	          checkoutDir(config.workspacePath, co.id),
70	          assetInfo.filename ?? "",
71	        ),
72	        snapshotPath: null,
73	        uploadProgress: null,
74	        errorMessage: null,
75	      };
76	      active.set(co.id, record);
77	      watchFile(co.id, record.workspacePath);
78	    }
79	    notify();
80	  } catch (e) {
81	    log.warn("Failed to load active checkouts from server:", e);
82	  }
83	}
84	
85	// ── Checkout ──────────────────────────────────────────────────────────────────
86	
87	export async function checkout(
88	  token: string,
89	  assetId?: string,
90	): Promise<{ checkoutId: string; workspacePath: string }> {
91	  const config = getConfig();
92	
93	  const res = await apiStartCheckout({
94	    token,
95	    asset_id: assetId,
96	    device_id: config.deviceId,
97	    helper_version: config.helperVersion,
98	    computer_id: config.deviceName,
99	  });
100	
101	  const { checkout_id, asset, root_mappings } = res;
102	
103	  // Merge server root_mappings with locally saved paths
104	  const localMappings = config.rootMappings;
105	  const mergedMappings: RootMapping[] = root_mappings.map((rm: any) => {
106	    const local = localMappings.find((l) => l.root_id === rm.root_id);
107	    return {
108	      root_id: rm.root_id,
109	      display_name: rm.display_name ?? rm.root_id,
110	      local_path: local?.local_path ?? rm.local_path ?? "",
111	      marker_verified: local?.marker_verified ?? false,
112	    };
113	  });
114	
115	  // Double-check each mapping's local path is still pointing at the right folder level
116	  for (const mapping of mergedMappings) {
117	    if (!mapping.local_path) continue;
118	    const vResult = validateRoot(mapping.local_path, mapping.root_id);
119	    if (!vResult.ok) {
120	      if (vResult.reason === "too_deep" || vResult.reason === "too_shallow") {
121	        // Auto-correct in memory for this checkout — user should fix in Settings
122	        log.warn(`Root path level mismatch for "${mapping.root_id}" — correcting to ${vResult.suggestedPath}`);
123	        mapping.local_path = vResult.suggestedPath;
124	      } else if (vResult.reason === "wrong_root_id") {
125	        throw new Error(
126	          `Folder mapping for "${mapping.root_id}" points to the wrong NAS root ("${vResult.actual}"). Please fix your folder mappings in Settings.`,
127	        );
128	      }
129	      // no_marker and forbidden are non-blocking here — resolveAssetPath will fail if path is truly wrong
130	    }
131	  }
132	
133	  let sourcePath: string;
134	  try {
135	    sourcePath = resolveAssetPath(
136	      asset.relative_path.split("/")[0] ?? asset.relative_path.split("\\")[0],
137	      asset.relative_path,
138	      mergedMappings,
139	    );
140	  } catch {
141	    // Fall back: try all mappings
142	    throw new Error(
143	      `No local path configured for this asset. Please set up your folder mappings in Settings.`,
144	    );
145	  }
146	
147	  if (!existsSync(sourcePath)) {
148	    throw new Error(
149	      `File not found locally: ${sourcePath}\n\nIt may not have synced yet. Check your Seafile or Synology Drive client.`,
150	    );
151	  }
152	
153	  const copied = await copyToWorkspace(
154	    sourcePath,
155	    checkout_id,
156	    asset.filename,
157	    config.workspacePath,
158	  );
159	
160	  const destDir = checkoutDir(config.workspacePath, checkout_id);
161	  writeCheckoutMeta(destDir, {
162	    checkout_id,
163	    asset_id: asset.asset_id,
164	    root_id: asset.relative_path.split("/")[0],
165	    relative_path: asset.relative_path,
166	    filename: asset.filename,
167	    checked_out_at: new Date().toISOString(),
168	    source_hash: asset.expected_hash ?? copied.hash,
169	    source_size: asset.expected_size ?? copied.size,
170	    dam_url: `${config.damUrl}/assets/${asset.asset_id}`,
171	  });
172	
173	  const record: CheckoutRecord = {
174	    id: checkout_id,
175	    assetId: asset.asset_id,
176	    userId: "",
177	    deviceId: config.deviceId,
178	    status: "active",
179	    checkedOutAt: new Date().toISOString(),
180	    checkedInAt: null,
181	    filename: asset.filename,
182	    relativePath: asset.relative_path,
183	    rootId: asset.relative_path.split("/")[0],
184	    sourceHash: asset.expected_hash ?? copied.hash,
185	    sourceSize: asset.expected_size ?? copied.size,
186	    workspacePath: copied.workspacePath,
187	    snapshotPath: null,
188	    uploadProgress: null,
189	    errorMessage: null,
190	  };
191	
192	  active.set(checkout_id, record);
193	  watchFile(checkout_id, copied.workspacePath);
194	  notify();
195	
196	  if (res.open_after_checkout) {
197	    await shell.openPath(copied.workspacePath);
198	  }
199	
200	  return { checkoutId: checkout_id, workspacePath: copied.workspacePath };
201	}
202	
203	// ── Check-in ──────────────────────────────────────────────────────────────────
204	
205	export async function checkin(checkoutId: string): Promise<void> {
206	  const record = active.get(checkoutId);
207	  if (!record) throw new Error(`Checkout ${checkoutId} not found`);
208	
209	  const config = getConfig();
210	
211	  updateStatus(checkoutId, "checkin_queued");
212	
213	  if (!existsSync(record.workspacePath)) {
214	    throw new Error(`Workspace file missing: ${record.workspacePath}`);
215	  }
216	
217	  // Wait for file to stop saving
218	  await waitForFileStable(record.workspacePath);
219	
220	  // Snapshot
221	  const snap = await createSnapshot(
222	    record.workspacePath,
223	    checkoutId,
224	    record.filename,
225	    config.workspacePath,
226	  );
227	
228	  // Tell DAM we're about to upload
229	  const instructions = await apiPrepareCheckin({
230	    checkout_id: checkoutId,
231	    snapshot_hash: snap.hash,
232	    snapshot_size: snap.size,
233	  });
234	
235	  record.snapshotPath = snap.snapshotPath;
236	
237	  // Enqueue async upload
238	  enqueue({
239	    checkoutId,
240	    snapshotPath: snap.snapshotPath,
241	    uploadMethod: "synology_file_station",
242	    synologyUrl: instructions.upload_instructions.synology_url,
243	    synologyPort: instructions.upload_instructions.synology_port,
244	    relativePath: instructions.upload_instructions.relative_path,
245	    filename: instructions.upload_instructions.filename,
246	    tempSuffix: instructions.upload_instructions.temp_suffix,
247	    retryCount: 0,
248	    addedAt: Date.now(),
249	  });
250	
251	  updateStatus(checkoutId, "uploading");
252	  notify();
253	}
254	
255	// ── Discard ───────────────────────────────────────────────────────────────────
256	
257	export async function discard(checkoutId: string): Promise<void> {
258	  await apiDiscard(checkoutId);
259	  stopWatcher(checkoutId);
260	  active.delete(checkoutId);
261	  notify();
262	}
263	
264	// ── Reveal ────────────────────────────────────────────────────────────────────
265	
266	export function revealFile(checkoutId: string): void {
267	  const record = active.get(checkoutId);
268	  if (!record || !existsSync(record.workspacePath)) return;
269	  shell.showItemInFolder(record.workspacePath);
270	}
271	
272	export function openFile(checkoutId: string): void {
273	  const record = active.get(checkoutId);
274	  if (!record || !existsSync(record.workspacePath)) return;
275	  shell.openPath(record.workspacePath);
276	}
277	
278	// ── Accessors ─────────────────────────────────────────────────────────────────
279	
280	export function getActiveCheckouts(): CheckoutRecord[] {
281	  return Array.from(active.values());
282	}
283	
284	export function updateUploadProgress(checkoutId: string, percent: number): void {
285	  const record = active.get(checkoutId);
286	  if (!record) return;
287	  record.uploadProgress = percent;
288	  if (percent >= 100) {
289	    record.status = "complete";
290	    active.delete(checkoutId);
291	    stopWatcher(checkoutId);
292	  }
293	  notify();
294	}
295	
296	function updateStatus(checkoutId: string, status: CheckoutRecord["status"]): void {
297	  const record = active.get(checkoutId);
298	  if (!record) return;
299	  record.status = status;
300	  notify();
301	}
302	
303	// ── File watcher ──────────────────────────────────────────────────────────────
304	
305	function watchFile(checkoutId: string, filePath: string): void {
306	  if (!existsSync(filePath)) return;
307	  stopWatcher(checkoutId);
308	
309	  const watcher = chokidar.watch(filePath, {
310	    persistent: true,
311	    ignoreInitial: true,
312	    awaitWriteFinish: { stabilityThreshold: 2000, pollInterval: 300 },
313	  });
314	
315	  watcher.on("change", () => {
316	    const record = active.get(checkoutId);
317	    if (!record) return;
318	    log.debug(`File changed: ${filePath}`);
319	    notify();
320	  });
321	
322	  watcher.on("unlink", () => {
323	    const record = active.get(checkoutId);
324	    if (!record) return;
325	    record.errorMessage = "Workspace file was deleted.";
326	    updateStatus(checkoutId, "error");
327	  });
328	
329	  watchers.set(checkoutId, watcher);
330	}
331	
332	function stopWatcher(checkoutId: string): void {
333	  const w = watchers.get(checkoutId);
334	  if (w) {
335	    w.close();
336	    watchers.delete(checkoutId);
337	  }
338	}
