1	/**
2	 * Local config — persisted to userData/config.json.
3	 * Does NOT store secrets (those go in the OS keychain via credentials.ts).
4	 */
5	
6	import { app } from "electron";
7	import { join } from "path";
8	import { readFileSync, writeFileSync, mkdirSync } from "fs";
9	import { homedir, hostname } from "os";
10	import { LocalConfig } from "@shared/types";
11	import { HELPER_VERSION } from "@shared/constants";
12	import { log } from "./logger";
13	
14	const CONFIG_PATH = join(app.getPath("userData"), "config.json");
15	
16	function defaultWorkspacePath(): string {
17	  const home = homedir();
18	  return process.platform === "win32"
19	    ? join("C:\\POP-DAM-Workspace")
20	    : join(home, "POP-DAM-Workspace");
21	}
22	
23	function defaultConfig(): LocalConfig {
24	  return {
25	    deviceId: null,
26	    deviceName: hostname(),
27	    deviceOs: process.platform === "win32" ? "windows" : "macos",
28	    helperVersion: HELPER_VERSION,
29	    damUrl: "https://dam.designflow.app",
30	    supabaseUrl: "",
31	    supabaseAnonKey: "",
32	    workspacePath: defaultWorkspacePath(),
33	    rootMappings: [],
34	  };
35	}
36	
37	let _config: LocalConfig | null = null;
38	
39	export function loadConfig(): LocalConfig {
40	  if (_config) return _config;
41	  try {
42	    const raw = readFileSync(CONFIG_PATH, "utf-8");
43	    _config = { ...defaultConfig(), ...JSON.parse(raw) };
44	  } catch {
45	    _config = defaultConfig();
46	  }
47	  return _config!;
48	}
49	
50	export function saveConfig(updates: Partial<LocalConfig>): LocalConfig {
51	  const current = loadConfig();
52	  _config = { ...current, ...updates };
53	  try {
54	    mkdirSync(app.getPath("userData"), { recursive: true });
55	    writeFileSync(CONFIG_PATH, JSON.stringify(_config, null, 2), "utf-8");
56	  } catch (e) {
57	    log.error("Failed to save config:", e);
58	  }
59	  return _config!;
60	}
61	
62	export function getConfig(): LocalConfig {
63	  return loadConfig();
64	}
