1	/**
2	 * Synology File Station API client.
3	 *
4	 * Authenticates as the actual user (not a service account) so that
5	 * Synology audit logs record the correct username for every upload.
6	 *
7	 * API reference: Synology File Station API Guide
8	 * Base URL: https://<nas>:<port>/webapi/
9	 */
10	
11	import { createReadStream, statSync, readFileSync, writeFileSync, mkdirSync } from "fs";
12	import { basename, dirname } from "path";
13	import { log } from "./logger";
14	import { loadToken, storeToken, deleteToken } from "./credentials";
15	
16	const SID_KEY = "synology_sid";
17	
18	export interface SynologyConfig {
19	  url: string;       // e.g. "https://nyc-synology.example"
20	  port: string;      // e.g. "5001"
21	  username: string;  // Synology account
22	  password: string;  // loaded from keychain
23	}
24	
25	function apiBase(config: SynologyConfig): string {
26	  return `${config.url.replace(/\/$/, "")}:${config.port}/webapi`;
27	}
28	
29	// ── Session management ────────────────────────────────────────────────────────
30	
31	export async function login(config: SynologyConfig): Promise<string> {
32	  const cached = await loadToken(SID_KEY);
33	  if (cached) return cached;
34	
35	  const url =
36	    `${apiBase(config)}/auth.cgi` +
37	    `?api=SYNO.API.Auth&version=3&method=login` +
38	    `&account=${encodeURIComponent(config.username)}` +
39	    `&passwd=${encodeURIComponent(config.password)}` +
40	    `&session=FileStation&format=sid`;
41	
42	  const res = await fetch(url);
43	  const json = await res.json();
44	  if (!json.success) {
45	    throw new Error(`Synology login failed: error code ${json.error?.code}`);
46	  }
47	
48	  const sid: string = json.data.sid;
49	  await storeToken(SID_KEY, sid);
50	  return sid;
51	}
52	
53	export async function logout(config: SynologyConfig): Promise<void> {
54	  const sid = await loadToken(SID_KEY);
55	  if (!sid) return;
56	  await fetch(
57	    `${apiBase(config)}/auth.cgi?api=SYNO.API.Auth&version=1&method=logout&session=FileStation&_sid=${sid}`,
58	  ).catch(() => {/* best-effort */});
59	  await deleteToken(SID_KEY);
60	}
61	
62	// ── Upload ────────────────────────────────────────────────────────────────────
63	
64	export interface UploadProgress {
65	  bytesUploaded: number;
66	  totalBytes: number;
67	  percent: number;
68	}
69	
70	/**
71	 * Upload a file to Synology using File Station upload API.
72	 * Uploads to a temporary filename first, then renames to final name.
73	 *
74	 * @param config      Synology connection + auth config
75	 * @param localPath   Local file to upload (snapshot)
76	 * @param shareName   Synology share name, e.g. "Design_Hot"
77	 * @param remotePath  Relative path within the share, e.g. "Walmart/2026/Spring/WallArt"
78	 * @param tempName    Temporary filename to upload as (e.g. "art.ai.__pop_uploading_abc.tmp")
79	 * @param finalName   Final filename after rename (e.g. "art.ai")
80	 * @param onProgress  Optional progress callback
81	 */
82	export async function uploadFile(
83	  config: SynologyConfig,
84	  localPath: string,
85	  shareName: string,
86	  remoteDir: string,
87	  tempName: string,
88	  finalName: string,
89	  onProgress?: (p: UploadProgress) => void,
90	): Promise<void> {
91	  const sid = await login(config);
92	  const totalBytes = statSync(localPath).size;
93	  const destFolder = `/${shareName}/${remoteDir}`.replace(/\/\//g, "/").replace(/\/$/, "");
94	
95	  // Upload to temp filename
96	  log.info(`Uploading ${localPath} → ${destFolder}/${tempName}`);
97	  await uploadChunked(config, sid, localPath, destFolder, tempName, totalBytes, onProgress);
98	
99	  // Rename temp → final
100	  log.info(`Renaming ${tempName} → ${finalName}`);
101	  await renameFile(config, sid, destFolder, tempName, finalName);
102	}
103	
104	async function uploadChunked(
105	  config: SynologyConfig,
106	  sid: string,
107	  localPath: string,
108	  destFolder: string,
109	  destFilename: string,
110	  totalBytes: number,
111	  onProgress?: (p: UploadProgress) => void,
112	): Promise<void> {
113	  // Synology File Station supports multipart upload via SYNO.FileStation.Upload
114	  const uploadUrl = `${apiBase(config)}/entry.cgi`;
115	
116	  const formData = new FormData();
117	  formData.append("api", "SYNO.FileStation.Upload");
118	  formData.append("version", "2");
119	  formData.append("method", "upload");
120	  formData.append("path", destFolder);
121	  formData.append("create_parents", "true");
122	  formData.append("overwrite", "true");
123	  formData.append("_sid", sid);
124	
125	  // Read file into buffer (for files up to ~500MB this is fine;
126	  // for very large files a streaming approach would be needed)
127	  const fileBuffer = readFileSync(localPath);
128	  const blob = new Blob([fileBuffer]);
129	  formData.append("file", blob, destFilename);
130	
131	  onProgress?.({ bytesUploaded: 0, totalBytes, percent: 0 });
132	
133	  const res = await fetch(uploadUrl, {
134	    method: "POST",
135	    body: formData,
136	    headers: { Cookie: `id=${sid}` },
137	  });
138	
139	  const json = await res.json();
140	  if (!json.success) {
141	    // Session may have expired — clear cached SID and let caller retry
142	    if (json.error?.code === 119 || json.error?.code === 105) {
143	      await deleteToken(SID_KEY);
144	    }
145	    throw new Error(`Synology upload failed: error code ${json.error?.code}`);
146	  }
147	
148	  onProgress?.({ bytesUploaded: totalBytes, totalBytes, percent: 100 });
149	}
