23	/**
24	 * Resolve an asset's source path from its root_id + relative_path.
25	 * Throws if root_id is unmapped or relative_path is unsafe.
26	 */
27	export function resolveAssetPath(
28	  rootId: string,
29	  relativePath: string,
30	  rootMappings: RootMapping[],
31	): string {
32	  const mapping = rootMappings.find((m) => m.root_id === rootId);
33	  if (!mapping) throw new Error(`No local mapping for root_id "${rootId}"`);
34	
35	  const safeRelative = sanitizeRelativePath(relativePath);
36	  return join(mapping.local_path, safeRelative);
37	}
38	
39	/**
40	 * Reject relative paths that try to escape the root.
41	 */
42	function sanitizeRelativePath(p: string): string {
43	  // Normalize all separators
44	  const normalized = normalize(p.replace(/\\/g, "/"));
45	  // Reject absolute paths, UNC paths, drive letters, or traversals
46	  if (
47	    isAbsolute(normalized) ||
48	    normalized.startsWith("..") ||
49	    normalized.includes(".." + sep) ||
50	    /^[a-zA-Z]:/.test(normalized) ||
51	    normalized.startsWith("//") ||
52	    normalized.startsWith("\\\\")
53	  ) {
54	    throw new Error(`Unsafe relative path rejected: "${p}"`);
55	  }
56	  return normalized;
57	}
