126	// ── File stability check ──────────────────────────────────────────────────────
127	
128	export async function waitForFileStable(filePath: string): Promise<void> {
129	  let lastSize = -1;
130	  let lastMtime = -1;
131	  let stableCount = 0;
132	
133	  for (let attempt = 0; attempt < STABILITY_MAX_ATTEMPTS; attempt++) {
134	    await sleep(STABILITY_WAIT_MS);
135	
136	    if (!existsSync(filePath)) {
137	      throw new Error(`File disappeared during stability check: ${filePath}`);
138	    }
139	
140	    const stat = statSync(filePath);
141	    const size = stat.size;
142	    const mtime = stat.mtimeMs;
143	
144	    if (size === lastSize && mtime === lastMtime) {
145	      stableCount++;
146	      if (stableCount >= 2) {
147	        // Try to open for exclusive read to confirm not locked
148	        try {
149	          const fd = openSync(filePath, "r");
150	          closeSync(fd);
151	        } catch {
152	          // Still locked — keep waiting
153	          stableCount = 0;
154	          continue;
155	        }
156	        return; // stable
157	      }
158	    } else {
159	      stableCount = 0;
160	    }
161	
162	    lastSize = size;
163	    lastMtime = mtime;
164	  }
165	
166	  throw new Error(
167	    `File "${filePath}" did not stabilize after ${STABILITY_MAX_ATTEMPTS} checks. It may still be saving.`,
168	  );
169	}
