1	/**
2	 * Electron main process entry point.
3	 *
4	 * Startup sequence:
5	 *  1. Single-instance lock (prevent multiple copies)
6	 *  2. Register popdam:// protocol (Windows needs this before app.ready)
7	 *  3. App ready → create tray, init queue, load active checkouts
8	 *  4. Start heartbeat timer
9	 */
10	
11	import { app, BrowserWindow } from "electron";
12	import { electronApp, optimizer } from "@electron-toolkit/utils";
13	import { autoUpdater } from "electron-updater";
14	import { createTray, updateTrayIcon, showWindow } from "./tray";
15	import { registerIpcHandlers } from "./ipc";
16	import { registerProtocol } from "./protocol";
17	import { initQueue, setProgressCallback, processQueue } from "./uploadQueue";
18	import { loadActiveCheckouts, onCheckoutsChanged, updateUploadProgress } from "./checkoutManager";
19	import { heartbeat } from "./damClient";
20	import { loadConfig, getConfig } from "./config";
21	import { log } from "./logger";
22	import { startLocalServer } from "./localServer";
23	import { HEARTBEAT_INTERVAL_MS, HELPER_VERSION } from "@shared/constants";
24	import { sendToRenderer } from "./tray";
25	
26	// ── Single instance lock ──────────────────────────────────────────────────────
27	const gotLock = app.requestSingleInstanceLock();
28	if (!gotLock) {
29	  app.quit();
30	  process.exit(0);
31	}
32	
33	// ── Protocol registration (must happen before app.ready on Windows) ───────────
34	if (process.defaultApp) {
35	  // Dev mode — register with electron executable
36	  if (process.argv.length >= 2) {
37	    app.setAsDefaultProtocolClient("popdam", process.execPath, [process.argv[1]]);
38	  }
39	} else {
40	  app.setAsDefaultProtocolClient("popdam");
41	}
42	
43	registerProtocol();
44	
45	// ── macOS: hide dock icon (we're a menu-bar app) ──────────────────────────────
46	if (process.platform === "darwin") {
47	  app.dock?.hide();
48	}
49	
50	// ── App ready ─────────────────────────────────────────────────────────────────
51	app.whenReady().then(async () => {
52	  electronApp.setAppUserModelId("com.popcreations.popdam-helper");
53	
54	  app.on("browser-window-created", (_, window) => {
55	    optimizer.watchWindowShortcuts(window);
56	  });
57	
58	  const config = loadConfig();
59	  registerIpcHandlers();
60	  createTray();
61	  startLocalServer();
62	
63	  // First run: open the popup automatically so the user knows the app is running
64	  // and can complete setup (root mappings, workspace folder).
65	  if (!config.deviceId || config.rootMappings.length === 0) {
66	    setTimeout(() => showWindow(), 600);
67	  }
68	
69	  // Init SQLite upload queue
70	  initQueue();
71	  setProgressCallback((checkoutId, percent) => {
72	    updateUploadProgress(checkoutId, percent);
73	    sendToRenderer("checkouts-changed");
74	    updateTrayIcon();
75	  });
76	
77	  // Resume any queued uploads from before restart
78	  processQueue();
79	
80	  // Load active checkouts from server
81	  await loadActiveCheckouts();
82	  updateTrayIcon();
83	
84	  // Notify renderer whenever checkout state changes
85	  onCheckoutsChanged(() => {
86	    sendToRenderer("checkouts-changed");
87	    updateTrayIcon();
88	  });
89	
90	  // Heartbeat — reads deviceId dynamically so it works after OAuth sign-in
91	  setInterval(async () => {
92	    const cfg = getConfig();
93	    if (cfg.deviceId) {
94	      await heartbeat({ device_id: cfg.deviceId });
95	    }
96	  }, HEARTBEAT_INTERVAL_MS);
97	
98	  // Auto-update check — silently checks GitHub for a newer release
99	  autoUpdater.logger = log;
100	  autoUpdater.checkForUpdatesAndNotify().catch((e: unknown) => {
101	    log.debug("Auto-update check skipped:", (e as Error).message);
102	  });
103	
104	  log.info(`POP DAM Helper v${HELPER_VERSION} started`);
105	});
106	
107	// ── macOS: don't quit when all windows close ──────────────────────────────────
108	app.on("window-all-closed", (e) => {
109	  e.preventDefault();
110	});
111	
112	// ── Clean shutdown ────────────────────────────────────────────────────────────
113	app.on("before-quit", () => {
114	  log.info("POP DAM Helper shutting down");
115	});
