123	async function handleCreateToken(req: Request): Promise<Response> {
124	  const userId = await getUserId(req);
125	  if (!userId) return err("Unauthorized", 401);
126	
127	  const body = await req.json();
128	  const { action, asset_id, checkout_id } = body;
129	
130	  if (!action || !["checkout", "checkin", "open", "reveal", "discard"].includes(action)) {
131	    return err("Invalid action");
132	  }
133	  if (action === "checkout" && !asset_id) return err("asset_id required for checkout");
134	  if (["checkin", "open", "reveal", "discard"].includes(action) && !checkout_id && !asset_id) {
135	    return err("checkout_id or asset_id required");
136	  }
137	
138	  const db = serviceClient();
139	
140	  // For checkout, verify asset exists and is not already locked
141	  if (action === "checkout" && asset_id) {
142	    const { data: asset } = await db
143	      .from("assets")
144	      .select("id, filename, relative_path, quick_hash, file_size")
145	      .eq("id", asset_id)
146	      .eq("is_deleted", false)
147	      .single();
148	    if (!asset) return err("Asset not found or deleted");
149	
150	    const { data: existing } = await db
151	      .from("asset_checkouts")
152	      .select("id, user_id")
153	      .eq("asset_id", asset_id)
154	      .in("status", ["active", "checkin_queued", "uploading", "verifying"])
155	      .maybeSingle();
156	
157	    if (existing && existing.user_id !== userId) {
158	      return err("Asset is currently checked out by another user", 409);
159	    }
160	  }
161	
162	  const tokenId = randomHex(16); // 32 hex chars
163	  const expiresAt = new Date(Date.now() + 5 * 60 * 1000).toISOString(); // 5 minutes
164	
165	  const { error } = await db.from("helper_tokens").insert({
166	    id: tokenId,
167	    user_id: userId,
168	    action,
169	    asset_id: asset_id ?? null,
170	    checkout_id: checkout_id ?? null,
171	    expires_at: expiresAt,
172	  });
173	  if (error) return err(`Failed to create token: ${error.message}`, 500);
174	
175	  // Build the popdam:// URL
176	  const params = new URLSearchParams({ token: tokenId });
177	  if (asset_id) params.set("assetId", asset_id);
178	  if (checkout_id) params.set("checkoutId", checkout_id);
179	  const url = `popdam://${action}?${params.toString()}`;
180	
181	  return json({ ok: true, token: tokenId, url, expires_at: expiresAt });
182	}
