505	corsServe(async (req: Request): Promise<Response> => {
506	  const url = new URL(req.url);
507	  const path = url.pathname.replace(/^\/helper-api/, "");
508	  const method = req.method;
509	
510	  if (method === "POST" && path === "/register-device") return handleRegisterDevice(req);
511	  if (method === "GET" && path === "/config") return handleGetConfig(req);
512	  if (method === "POST" && path === "/tokens") return handleCreateToken(req);
513	  if (method === "POST" && path === "/checkouts/start") return handleStartCheckout(req);
514	  if (method === "POST" && path === "/checkouts/prepare-checkin") return handlePrepareCheckin(req);
515	  if (method === "POST" && path === "/checkouts/complete-checkin") return handleCompleteCheckin(req);
516	  if (method === "POST" && path === "/checkouts/discard") return handleDiscard(req);
517	  if (method === "POST" && path === "/checkouts/heartbeat") return handleHeartbeat(req);
518	  if (method === "GET" && path === "/checkouts/open") return handleGetOpenCheckouts(req);
519	  if (method === "POST" && path === "/logs") return handleLogs(req);
520	  if (method === "POST" && path === "/admin/force-discard") return handleAdminForceDiscard(req);
521	
522	  return err("Not found", 404);
523	});
