1	/**
2	 * Local HTTP server — lets the web DAM talk to the helper directly over localhost,
3	 * bypassing the cloud roundtrip for directory browsing and other fast operations.
4	 *
5	 * Runs on a fixed port (47380) so the web app always knows where to find it.
6	 * CORS is restricted to *.designflow.app and localhost.
7	 *
8	 * Endpoints:
9	 *   GET /status          — health check; returns { ok, version, roots[] }
10	 *   GET /browse?path=X   — list directory; path="" lists configured roots
11	 */
12	
13	import { createServer, IncomingMessage, ServerResponse } from "http";
14	import { readdirSync, statSync } from "fs";
15	import { join } from "path";
16	import { getConfig } from "./config";
17	import { log } from "./logger";
18	import { HELPER_VERSION } from "@shared/constants";
19	
20	export const LOCAL_SERVER_PORT = 47380;
21	
22	const ALLOWED_ORIGINS = [
23	  /^https?:\/\/localhost(:\d+)?$/,
24	  /^https:\/\/[a-z0-9-]+\.designflow\.app$/,
25	];
26	
27	function isAllowedOrigin(origin: string | undefined): boolean {
28	  if (!origin) return true; // non-browser request
29	  return ALLOWED_ORIGINS.some((p) => p.test(origin));
30	}
31	
32	function send(res: ServerResponse, status: number, body: unknown, origin?: string): void {
33	  const json = JSON.stringify(body);
34	  res.writeHead(status, {
35	    "Content-Type": "application/json",
36	    "Content-Length": Buffer.byteLength(json),
37	    ...(origin && isAllowedOrigin(origin)
38	      ? {
39	          "Access-Control-Allow-Origin": origin,
40	          "Access-Control-Allow-Methods": "GET, OPTIONS",
41	          "Access-Control-Allow-Headers": "Content-Type",
42	          Vary: "Origin",
43	        }
44	      : {}),
45	  });
46	  res.end(json);
47	}
48	
49	// ── /browse ───────────────────────────────────────────────────────────────────
50	
51	interface DirEntry {
52	  name: string;
53	  is_dir: boolean;
54	  size?: number;
55	  modified?: string;
56	}
57	
58	function browseLocal(requestPath: string): { path: string; entries: DirEntry[] } {
59	  const config = getConfig();
60	  const roots = config.rootMappings.filter((r) => r.local_path);
61	
62	  // Empty path → list configured roots
63	  if (!requestPath || requestPath === "/") {
64	    return {
65	      path: "",
66	      entries: roots.map((r) => ({
67	        name: r.root_id,
68	        is_dir: true,
69	      })),
70	    };
71	  }
72	
73	  // Resolve path: first segment is root_id, rest is subpath
74	  const parts = requestPath.replace(/\\/g, "/").replace(/^\//, "").split("/");
75	  const rootId = parts[0];
76	  const subPath = parts.slice(1).join("/");
77	
78	  const root = roots.find((r) => r.root_id === rootId);
79	
80	  // If not a known root_id, try treating as an absolute local path (power-user mode)
81	  const localBase = root ? root.local_path : requestPath;
82	  const localPath = root && subPath ? join(localBase, subPath) : localBase;
83	
84	  const entries: DirEntry[] = [];
85	  const items = readdirSync(localPath);
86	
87	  for (const name of items) {
88	    // Skip hidden files
89	    if (name.startsWith(".")) continue;
90	    try {
91	      const st = statSync(join(localPath, name));
92	      entries.push({
93	        name,
94	        is_dir: st.isDirectory(),
95	        size: st.isDirectory() ? undefined : st.size,
96	        modified: st.mtime.toISOString(),
97	      });
98	    } catch {
99	      // skip entries we can't stat (broken symlinks, permission errors)
100	    }
101	  }
102	
103	  return { path: requestPath, entries };
104	}
