108	export function startLocalServer(): void {
109	  const server = createServer((req: IncomingMessage, res: ServerResponse) => {
110	    const origin = req.headers.origin;
111	    const url = new URL(req.url ?? "/", `http://localhost:${LOCAL_SERVER_PORT}`);
112	
113	    // Preflight
114	    if (req.method === "OPTIONS") {
115	      if (isAllowedOrigin(origin)) {
116	        res.writeHead(204, {
117	          "Access-Control-Allow-Origin": origin ?? "*",
118	          "Access-Control-Allow-Methods": "GET, OPTIONS",
119	          "Access-Control-Allow-Headers": "Content-Type",
120	          "Access-Control-Max-Age": "86400",
121	        });
122	      } else {
123	        res.writeHead(403);
124	      }
125	      res.end();
126	      return;
127	    }
128	
129	    if (req.method !== "GET") {
130	      send(res, 405, { ok: false, error: "Method not allowed" }, origin);
131	      return;
132	    }
133	
134	    if (!isAllowedOrigin(origin)) {
135	      send(res, 403, { ok: false, error: "Forbidden origin" });
136	      return;
137	    }
138	
139	    try {
140	      if (url.pathname === "/status") {
141	        const config = getConfig();
142	        send(res, 200, {
143	          ok: true,
144	          version: HELPER_VERSION,
145	          roots: config.rootMappings.map((r) => ({
146	            root_id: r.root_id,
147	            display_name: r.display_name,
148	            local_path: r.local_path,
149	          })),
150	        }, origin);
151	        return;
152	      }
153	
154	      if (url.pathname === "/browse") {
155	        const path = url.searchParams.get("path") ?? "";
156	        const result = browseLocal(path);
157	        send(res, 200, {
158	          ok: true,
159	          path: result.path,
160	          entries: result.entries,
161	          listed_at: new Date().toISOString(),
162	        }, origin);
163	        return;
164	      }
165	
166	      send(res, 404, { ok: false, error: "Not found" }, origin);
167	    } catch (e: unknown) {
168	      const msg = e instanceof Error ? e.message : String(e);
169	      log.error("Local server error:", msg);
170	      send(res, 500, { ok: false, error: msg }, origin);
171	    }
172	  });
173	
174	  server.on("error", (e: NodeJS.ErrnoException) => {
175	    if (e.code === "EADDRINUSE") {
176	      log.warn(`Port ${LOCAL_SERVER_PORT} already in use — local server not started`);
177	    } else {
178	      log.error("Local server error:", e.message);
179	    }
180	  });
181	
182	  server.listen(LOCAL_SERVER_PORT, "127.0.0.1", () => {
183	    log.info(`Local server listening on http://127.0.0.1:${LOCAL_SERVER_PORT}`);
184	  });
185	}
